using System.ComponentModel;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Shared state ──────────────────────────────────────────────────────────────
var notes = new List<(string Title, string Content)>();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

// ── Tool definitions ──────────────────────────────────────────────────────────

[Description("Search the web for information on a query. Returns relevant results with snippets.")]
async Task<string> SearchWeb(
    [Description("The search query to look up")] string query)
{
    try
    {
        var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}"
                + "&format=json&no_html=1&t=ResearchAgent";
        var json = await httpClient.GetStringAsync(url);
        var doc = JsonDocument.Parse(json);
        var results = new List<string>();

        var abstractText = doc.RootElement.GetProperty("AbstractText").GetString();
        if (!string.IsNullOrWhiteSpace(abstractText))
        {
            var source = doc.RootElement.GetProperty("AbstractSource").GetString();
            var sourceUrl = doc.RootElement.GetProperty("AbstractURL").GetString();
            results.Add($"[{source}] ({sourceUrl})\n{abstractText}");
        }

        if (doc.RootElement.TryGetProperty("RelatedTopics", out var topics))
        {
            foreach (var topic in topics.EnumerateArray().Take(6))
            {
                if (topic.TryGetProperty("Text", out var text))
                {
                    var firstUrl = topic.TryGetProperty("FirstURL", out var fu)
                        ? fu.GetString() : null;
                    results.Add($"- {text.GetString()}"
                        + (firstUrl is not null ? $" ({firstUrl})" : ""));
                }
            }
        }

        return results.Count > 0
            ? string.Join("\n\n", results)
            : "No results found. Try rephrasing the query.";
    }
    catch (Exception ex)
    {
        return $"Search error: {ex.Message}. Try a different query.";
    }
}

[Description("Save a research note with a title and content. Use to record key findings.")]
string SaveNote(
    [Description("Short title for the note")] string title,
    [Description("The finding or information to record")] string content)
{
    notes.Add((title, content));
    Console.WriteLine($"  📝 Note saved: \"{title}\"");
    return $"Saved note \"{title}\" ({notes.Count} total notes).";
}

[Description("Retrieve all previously saved research notes to review before summarizing.")]
string GetNotes()
{
    if (notes.Count == 0)
        return "No notes have been saved yet.";

    return string.Join("\n\n", notes.Select((n, i) =>
        $"── Note {i + 1}: {n.Title} ──\n{n.Content}"));
}

// ── Build the AI agent ────────────────────────────────────────────────────────

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(SaveNote),
    AIFunctionFactory.Create(GetNotes),
};

var agent = new ChatClientAgent(chatClient, new ChatClientAgentOptions
{
    Name = "ResearchAgent",
    Description = "Researches topics by searching the web and collecting notes, then summarizes findings.",
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
        Tools = tools,
    },
});

// ── Interactive loop ──────────────────────────────────────────────────────────

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║        🔍 Research Agent             ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine("Enter a topic to research (or 'quit' to exit).\n");

while (true)
{
    Console.Write("Topic> ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notes.Clear();
    Console.WriteLine($"\n🔎 Researching \"{topic}\"...\n");

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System,
            """
            You are a thorough research assistant with access to web search and note-taking tools.

            When given a topic, follow these steps:
            1. Perform at least 3 web searches with varied queries to get broad coverage.
            2. After each search, save the most important findings as notes.
            3. Once you have gathered enough information, retrieve your notes.
            4. Write a comprehensive, well-structured summary of your findings with source attributions.

            Always gather information before summarizing. Be factual and cite sources.
            """),
        new(ChatRole.User, $"Research the following topic and provide a detailed summary: {topic}"),
    };

    var session = new ChatClientAgentSession();
    var response = await agent.RunAsync(
        messages, session, options: null, CancellationToken.None);

    Console.WriteLine("\n══════════ Research Summary ══════════\n");

    foreach (var message in response.Messages)
    {
        if (message.Role == ChatRole.Assistant && !string.IsNullOrWhiteSpace(message.Text))
            Console.WriteLine(message.Text);
    }

    Console.WriteLine("\n══════════════════════════════════════\n");
}

Console.WriteLine("Goodbye!");

